WITH nearest AS (SELECT p.cleabs, p.nom, (SELECT v.id FROM ways_vertices_pgr v ORDER BY v.geom <-> p.geom LIMIT 1) AS vid FROM mission_pois p WHERE p.role = 'defense' LIMIT 2) SELECT a.nom AS start, b.nom AS end, agg.cost FROM nearest a, nearest b, LATERAL (SELECT sum(cost) AS cost FROM pgr_dijkstra('SELECT id, source, target, cost, reverse_cost FROM ways', a.vid, b.vid, directed := true) WHERE edge != -1) agg WHERE a.cleabs < b.cleabs LIMIT 5;
